properties.formula:
var number percent = If([Adder is Charge],If(IsNull([Related Adder - Adder Charge %]),[Total Cost],[Total Cost]*([Related Adder - Adder Charge %]/100)));
var number charge = If(IsNull([Charge Amount Override]),$percent,[Charge Amount Override]);

If(IsNull($charge),0,$charge)

var text returnTo =
"https://kin.quickbase.com/nav/app/br9kwm8bk/action/showpage/413110db-9eaf-49ea-98d9-37c1e5afb9af?pageIdV2=787d9748-b3a7-426d-aea8-2fda155643bc";

var text url =
URLRoot() & "db/" & Dbid() &
"?a=API_EditRecord" &
"&rid=" & [Record ID#] &
"&_fid_208=1" &  // Notify Rep Trigger = true
"&rdr=" & URLEncode($returnTo);

var bool hasPhone = not(Trim(ToText([Project - Closer - Office/ Home Phone])) = "");

If(
  not($hasPhone),
  "<span style='color:#888;'>No phone on file</span>",

  // If a final notified date exists, show it
  not(IsNull([Rep Notified Date - Call-out])),
  "<span style='color:#888;'>✓ Message sent " & ToText([Rep Notified Date - Call-out]) & "</span>",

  // If user just clicked and trigger is true, show Sending…
  [Notify Rep Trigger],
  "<span style='background:#fff7e6;border:1px solid #f0c36d;color:#8a6d3b;padding:6px 10px;border-radius:6px;font-weight:600;'>⏳ Sending…</span>",

  // Otherwise, show the blue button
  "<a href='" & $url & "' style='display:inline-block;padding:8px 14px;background-color:#007bff;color:#fff;text-decoration:none;border-radius:6px;font-weight:600;'>Notify Rep</a>"
)

var bool schedule = If([Related Adder - Install Scheduling Gate Type]="Scheduled Date",
[Project - Install Scheduled Start Date]>=ToDate([Scheduled Start Date]) 
or (IsNull([Project - Install Scheduled Start Date]) and not(IsNull([Scheduled Start Date]))));
var bool complete = If([Related Adder - Install Scheduling Gate Type]="Completed Date",
[Project - Install Scheduled Start Date]>=[Completed Date] or (IsNull([Project - Install Scheduled Start Date]) and not(IsNull([Completed Date]))));

$schedule or $complete
